                    TASK_TEMP_FILE_CLEANUP -> performTempFileCleanup(intent)
                    TASK_FULL_MAINTENANCE -> performFullMaintenance(intent)
                    else -> TaskResult(
                        taskType = taskType,
                        success = false,
                        message = "Unknown task type: $taskType"
                    )
                }

                taskResults[startId] = result
                sendCallbackResult(intent, result)

                Log.i(TAG, "Task completed: ${result.taskType}, success=${result.success}, message=${result.message}")

