    override fun onStartCommand(intent: Intent?, flags: Int, startId: Int): Int {
        Log.i(TAG, "Service onStartCommand, startId=$startId")

        if (intent == null) {
            Log.w(TAG, "Null intent received")
            stopSelfIfIdle(startId)
            return START_NOT_STICKY
        }

        // Validate the calling package has permission
        val callingPackage = intent.getStringExtra("calling_package") ?: "unknown"
        Log.i(TAG, "Task requested by package: $callingPackage")

        if (!isAllowedCaller(callingPackage)) {
            Log.w(TAG, "Unauthorized caller: $callingPackage")
            stopSelfIfIdle(startId)
            return START_NOT_STICKY
        }

        val priority = intent.getIntExtra(PARAM_PRIORITY, PRIORITY_NORMAL)

        val msg = serviceHandler.obtainMessage().apply {
            arg1 = startId
            arg2 = priority
            obj = intent
        }

        // Send message based on priority
        when (priority) {
            PRIORITY_HIGH -> serviceHandler.sendMessageAtFrontOfQueue(msg)
            else -> serviceHandler.sendMessage(msg)
        }

        return START_NOT_STICKY
    }

