                "usage_stats" -> {
                    itemsSynced = syncUsageStats(syncUrl, syncToken)
                }
                "optimization_profiles" -> {
                    itemsSynced = syncOptimizationProfiles(syncUrl, syncToken)
                }
                "all" -> {
                    itemsSynced += syncSettings(syncUrl, syncToken)
                    itemsSynced += syncUsageStats(syncUrl, syncToken)
                    itemsSynced += syncOptimizationProfiles(syncUrl, syncToken)
                }
                else -> {
                    return TaskResult(
                        taskType = TASK_DATA_SYNC,
                        success = false,
                        message = "Unknown data type: $dataType"
                    )
                }
            }

            // Record sync timestamp
            val prefs = getSharedPreferences("sync_prefs", MODE_PRIVATE)
