                .putLong("last_sync_${dataType}", System.currentTimeMillis())
                .putInt("last_sync_items_${dataType}", itemsSynced)
                .apply()

            return TaskResult(
                taskType = TASK_DATA_SYNC,
                success = true,
                message = "Data sync completed for type: $dataType",
                itemsProcessed = itemsSynced
            )
        } catch (e: Exception) {
            Log.e(TAG, "Data sync failed", e)
            return TaskResult(
                taskType = TASK_DATA_SYNC,
                success = false,
                message = "Data sync failed: ${e.message}"
            )
        }
