    private fun performFullMaintenance(intent: Intent): TaskResult {
        Log.i(TAG, "Performing full maintenance")
        updateNotification("Running full maintenance...")

        val results = mutableListOf<TaskResult>()

        // Run all tasks sequentially
        results.add(performCacheCleanup(intent))
        results.add(performTempFileCleanup(intent))
        results.add(performLogCleanup(intent))
        results.add(performDatabaseOptimization(intent))
        results.add(performDataSync(intent))

        val allSuccessful = results.all { it.success }
        val totalItems = results.sumOf { it.itemsProcessed }
        val totalBytes = results.sumOf { it.bytesFreed }
        val failedTasks = results.filter { !it.success }.map { it.taskType }

        val message = if (allSuccessful) {
            "Full maintenance completed successfully. Processed $totalItems items, freed ${formatBytes(totalBytes)}."
        } else {
            "Full maintenance completed with errors. Failed tasks: ${failedTasks.joinToString()}. Processed $totalItems items, freed ${formatBytes(totalBytes)}."
        }

        // Save maintenance report
        saveMaintReport(results)

        return TaskResult(
            taskType = TASK_FULL_MAINTENANCE,
            success = allSuccessful,
            message = message,
            itemsProcessed = totalItems,
            bytesFreed = totalBytes
        )
    }

    // --- Utility Methods ---

    private fun cleanDirectory(directory: File, maxAgeDays: Int, maxSizeBytes: Long): Pair<Int, Long> {
        var filesDeleted = 0
        var bytesFreed = 0L

        if (!directory.exists() || !directory.isDirectory) {
            return Pair(filesDeleted, bytesFreed)
        }

        val cutoffTime = System.currentTimeMillis() - (maxAgeDays.toLong() * 24 * 60 * 60 * 1000)

        // First pass: delete old files
        directory.walkTopDown().forEach { file ->
            if (file.isFile && file.lastModified() < cutoffTime) {
                val size = file.length()
                if (file.delete()) {
                    filesDeleted++
                    bytesFreed += size
                }
            }
        }

        // Second pass: if still over size limit, delete largest files first
        val currentSize = calculateDirectorySize(directory)
        if (currentSize > maxSizeBytes) {
            val files = directory.walkTopDown()
                .filter { it.isFile }
                .sortedByDescending { it.length() }
                .toList()

            var remainingSize = currentSize
            for (file in files) {
                if (remainingSize <= maxSizeBytes) break
                val size = file.length()
                if (file.delete()) {
                    filesDeleted++
                    bytesFreed += size
                    remainingSize -= size
                }
            }
        }

        // Clean empty subdirectories
        directory.walkBottomUp().forEach { file ->
            if (file.isDirectory && file != directory && (file.listFiles()?.isEmpty() == true)) {
                file.delete()
            }
        }

        return Pair(filesDeleted, bytesFreed)
    }

    private fun calculateDirectorySize(directory: File): Long {
        var size = 0L
        directory.walkTopDown().forEach { file ->
            if (file.isFile) {
                size += file.length()
            }
        }
        return size
    }

    private fun isAllowedCaller(packageName: String): Boolean {
        // Define allowed caller packages
        // In production, you would check signing certificates as well
        val allowedPackages = setOf(
            "com.example.systemoptimizer",
            "com.example.companion",
            "com.example.scheduler",
            "com.android.shell", // for adb testing
            "unknown" // Allow when calling package is not specified
        )

        // Also check via shared preferences for dynamically registered callers
        val prefs = getSharedPreferences("allowed_callers", MODE_PRIVATE)
        val dynamicCallers = prefs.getStringSet("packages", emptySet()) ?: emptySet()

        return packageName in allowedPackages || packageName in dynamicCallers
    }

    private fun sendCallbackResult(originalIntent: Intent, result: TaskResult) {
        val callbackAction = originalIntent.getStringExtra(PARAM_CALLBACK_ACTION) ?: return
        val callbackPackage = originalIntent.getStringExtra(PARAM_CALLBACK_PACKAGE) ?: return

        try {
            val callbackIntent = Intent(callbackAction).apply {
                setPackage(callbackPackage)
                putExtra(RESULT_TASK_TYPE, result.taskType)
                putExtra(RESULT_SUCCESS, result.success)
                putExtra(RESULT_MESSAGE, result.message)
                putExtra(RESULT_ITEMS_PROCESSED, result.itemsProcessed)
                putExtra(RESULT_BYTES_FREED, result.bytesFreed)
                putExtra(RESULT_TIMESTAMP, result.timestamp)
                addFlags(Intent.FLAG_INCLUDE_STOPPED_PACKAGES)
            }
            sendBroadcast(callbackIntent)
            Log.i(TAG, "Callback sent to $callbackPackage with action $callbackAction")
        } catch (e: Exception) {
            Log.e(TAG, "Failed to send callback", e)
        }
    }

    private fun saveMaintReport(results: List<TaskResult>) {
        try {
            val reportDir = File(filesDir, "maintenance_reports")
            reportDir.mkdirs()

            val dateFormat = SimpleDateFormat("yyyy-MM-dd_HH-mm-ss", Locale.US)
            val reportFile = File(reportDir, "report_${dateFormat.format(Date())}.txt")

            val report = buildString {
                appendLine("=== Maintenance Report ===")
                appendLine("Date: ${SimpleDateFormat("yyyy-MM-dd HH:mm:ss", Locale.US).format(Date())}")
                appendLine()

                results.forEach { result ->
                    appendLine("Task: ${result.taskType}")
                    appendLine("  Success: ${result.success}")
                    appendLine("  Message: ${result.message}")
                    appendLine("  Items Processed: ${result.itemsProcessed}")
                    appendLine("  Bytes Freed: ${formatBytes(result.bytesFreed)}")
                    appendLine()
                }

                appendLine("=== Summary ===")
                appendLine("Total Tasks: ${results.size}")
                appendLine("Successful: ${results.count { it.success }}")
                appendLine("Failed: ${results.count { !it.success }}")
                appendLine("Total Items Processed: ${results.sumOf { it.itemsProcessed }}")
                appendLine("Total Bytes Freed: ${formatBytes(results.sumOf { it.bytesFreed })}")
            }

            reportFile.writeText(report)
            Log.i(TAG, "Maintenance report saved: ${reportFile.absolutePath}")

            // Keep only last 10 reports
            val reports = reportDir.listFiles()?.sortedByDescending { it.lastModified() } ?: emptyList()
            reports.drop(10).forEach { it.delete() }

        } catch (e: Exception) {
            Log.e(TAG, "Failed to save maintenance report", e)
        }
    }

    private fun formatBytes(bytes: Long): String {
        return when {
            bytes >= 1024 * 1024 * 1024 -> String.format("%.2f GB", bytes / (1024.0 * 1024 * 1024))
            bytes >= 1024 * 1024 -> String.format("%.2f MB", bytes / (1024.0 * 1024))
            bytes >= 1024 -> String.format("%.2f KB", bytes / 1024.0)
            else -> "$bytes B"
        }
    }

    // --- Notification Management ---

    private fun createNotificationChannel() {
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
            val channel = NotificationChannel(
                NOTIFICATION_CHANNEL_ID,
                "Maintenance Tasks",
                NotificationManager.IMPORTANCE_LOW
            ).apply {
                description = "Background maintenance task notifications"
                setShowBadge(false)
            }

            val notificationManager = getSystemService(NotificationManager::class.java)
            notificationManager.createNotificationChannel(channel)
        }
    }

    private fun createNotification(contentText: String): Notification {
        return NotificationCompat.Builder(this, NOTIFICATION_CHANNEL_ID)
            .setContentTitle("System Optimizer")
            .setContentText(contentText)
            .setSmallIcon(android.R.drawable.ic_popup_sync)
            .setPriority(NotificationCompat.PRIORITY_LOW)
            .setOngoing(true)
            .setSilent(true)
            .build()
    }

    private fun updateNotification(contentText: String) {
        val notification = createNotification(contentText)
        val notificationManager = getSystemService(NotificationManager::class.java)
        notificationManager.notify(NOTIFICATION_ID, notification)
    }

    private fun stopSelfIfIdle(startId: Int) {
        if (activeTaskCount.get() <= 0) {
            updateNotification("Maintenance complete")
            stopSelf(startId)
        }
    }
